#!/usr/bin/env node

import { resolveConfig } from './lib/config.js'
import { cmdStatus } from './lib/cmd-status.js'
import { cmdInspect } from './lib/cmd-inspect.js'
import { cmdCompare } from './lib/cmd-compare.js'
import { cmdCreate } from './lib/cmd-create.js'
import { cmdFlags } from './lib/cmd-flags.js'

function cmdHelp(): void {
  process.stderr.write(
    'posthog-skill — PostHog analytics automation for branch 7361\n\n' +
      'Usage: node scripts/run.js <command> [options]\n\n' +
      'Commands: status | inspect [--live] | compare | create | flags [subcommand]\n' +
      'Options:  --dry-run  --help\n\n' +
      'Env: POSTHOG_PERSONAL_API_KEY  POSTHOG_PROJECT_ID  POSTHOG_HOST\n' +
      '     POSTHOG_ACH_INSIGHT_ID  POSTHOG_DASHBOARD_NAME\n',
  )
}

async function main(): Promise<void> {
  const args = process.argv.slice(2)

  if (args.length === 0 || args.includes('--help') || args.includes('-h')) {
    cmdHelp()
    process.exit(0)
  }

  const command = args[0]
  if (command === undefined) {
    cmdHelp()
    process.exit(0)
  }

  const flags = args.slice(1)
  const config = resolveConfig()

  switch (command) {
    case 'status':
      cmdStatus(config)
      break
    case 'inspect':
      await cmdInspect(flags, config)
      break
    case 'compare':
      await cmdCompare(flags, config)
      break
    case 'create':
      await cmdCreate(flags, config)
      break
    case 'flags':
      await cmdFlags(flags, config)
      break
    default:
      process.stderr.write(`Unknown command: ${command}\nRun with --help for usage.\n`)
      process.exit(2)
  }
}

main().catch((err) => {
  process.stderr.write(`Fatal: ${err instanceof Error ? err.message : String(err)}\n`)
  process.exit(1)
})

// ---------------------------------------------------------------------------
// PostHogError — typed error for non-2xx HTTP responses
// ---------------------------------------------------------------------------

export class PostHogError extends Error {
  readonly status: number
  readonly endpoint: string

  constructor(opts: { status: number; message: string; endpoint: string }) {
    super(opts.message)
    this.name = 'PostHogError'
    this.status = opts.status
    this.endpoint = opts.endpoint
  }
}

// ---------------------------------------------------------------------------
// Config & client option types
// ---------------------------------------------------------------------------

export interface PostHogConfig {
  host: string
  projectId: string
  token: string
}

export interface ClientOptions {
  retryDelayMs?: number
}

// ---------------------------------------------------------------------------
// Fetch abstraction (permissive for test mocks)
// ---------------------------------------------------------------------------

export interface MinimalResponse {
  status: number
  ok: boolean
  json(): Promise<unknown>
}

export type FetchFn = (url: string, options: RequestInit) => Promise<MinimalResponse>

// ---------------------------------------------------------------------------
// Dashboard types
// ---------------------------------------------------------------------------

export interface DashboardSummary {
  id: number
  name: string
  deleted: boolean
  [key: string]: unknown
}

export interface DashboardListResponse {
  count: number
  results: DashboardSummary[]
}

export interface DashboardTile {
  insight: { id: number; name: string } | null
  [key: string]: unknown
}

export interface Dashboard {
  id: number
  name: string
  tiles: DashboardTile[]
  [key: string]: unknown
}

// ---------------------------------------------------------------------------
// Insight types
// ---------------------------------------------------------------------------

export interface InsightQuerySource {
  kind: string
  series?: unknown[]
  breakdownFilter?: Record<string, unknown>
  dateRange?: Record<string, unknown>
  funnelsFilter?: Record<string, unknown>
  trendsFilter?: Record<string, unknown>
  [key: string]: unknown
}

export interface InsightVizNode {
  kind: 'InsightVizNode'
  source: InsightQuerySource
  [key: string]: unknown
}

export interface Insight {
  id: number
  name: string
  short_id?: string
  description?: string | null
  query?: InsightVizNode | InsightQuerySource | Record<string, unknown>
  filters?: Record<string, unknown>
  [key: string]: unknown
}

export interface InsightListResponse {
  count: number
  results: Insight[]
}

export interface HogQLResult {
  results: unknown[][]
  is_cached?: boolean
  [key: string]: unknown
}

// ---------------------------------------------------------------------------
// Feature flag types
// ---------------------------------------------------------------------------

export interface FeatureFlagSummary {
  id: number
  name: string
  key: string
  active: boolean
  deleted: boolean
  created_at: string
  updated_at: string
  tags: string[]
  filters: Record<string, unknown>
  version: number
  created_by: { id: number; email: string } | null
  ensure_experience_continuity: boolean
  is_remote_configuration: boolean
  evaluation_runtime: string
  status: string
}

export interface FeatureFlagListResponse {
  count: number
  next: string | null
  previous: string | null
  results: FeatureFlagSummary[]
}

export interface FeatureFlagListParams {
  search?: string
  active?: string
  type?: string
  limit?: number
  offset?: number
}

export interface FeatureFlagActivity {
  id: string
  activity: string
  detail: Record<string, unknown>
  created_at: string
  user: Record<string, unknown>
}

export interface FeatureFlagActivityResponse {
  results: FeatureFlagActivity[]
  next: string | null
  previous: string | null
  total_count: number
}

// ---------------------------------------------------------------------------
// Client interface
// ---------------------------------------------------------------------------

export interface PostHogClient {
  request(url: string, options: RequestInit): Promise<unknown>
  listDashboards(limit?: number): Promise<DashboardListResponse>
  createDashboard(name: string, tags: string[]): Promise<Dashboard>
  getDashboard(id: number): Promise<Dashboard>
  createInsight(name: string, query: Record<string, unknown>): Promise<Insight>
  createInsightOnDashboard(
    name: string,
    query: Record<string, unknown>,
    dashboardId: number,
  ): Promise<Insight>
  getInsightByShortId(shortId: string): Promise<InsightListResponse>
  runQuery(hogql: string): Promise<HogQLResult>
  listFeatureFlags(params?: FeatureFlagListParams): Promise<FeatureFlagListResponse>
  getFeatureFlag(id: number | string): Promise<FeatureFlagSummary>
  patchFeatureFlag(id: number | string, body: Record<string, unknown>): Promise<FeatureFlagSummary>
  createFeatureFlag(key: string, body?: Record<string, unknown>): Promise<FeatureFlagSummary>
  getFeatureFlagActivity(id: number | string, limit?: number): Promise<FeatureFlagActivityResponse>
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms))
}

// ---------------------------------------------------------------------------
// Client factory
// ---------------------------------------------------------------------------

export function createClient(
  config: PostHogConfig,
  fetchFn?: FetchFn,
  opts?: ClientOptions,
): PostHogClient {
  const fetch: FetchFn = fetchFn ?? (globalThis.fetch as FetchFn)
  const baseDelayMs = opts?.retryDelayMs ?? 1000

  const { host, projectId, token } = config
  const envBase = `${host}/api/environments/${projectId}`
  const projBase = `${host}/api/projects/${projectId}`

  // -------------------------------------------------------------------------
  // Core request method with 429 retry / error handling
  // -------------------------------------------------------------------------

  async function request(url: string, options: RequestInit): Promise<unknown> {
    const endpoint = url.replace(host, '').split('?')[0] ?? url

    const MAX_ATTEMPTS = 3
    let lastError: PostHogError | undefined

    for (let attempt = 0; attempt < MAX_ATTEMPTS; attempt++) {
      const response = await fetch(url, {
        ...options,
        headers: {
          Authorization: `Bearer ${token}`,
          ...(options.body ? { 'Content-Type': 'application/json' } : {}),
          ...(options.headers ?? {}),
        },
      })

      if (response.ok) {
        return response.json()
      }

      // 429 — rate limited: retry with exponential backoff
      if (response.status === 429) {
        const delayMs = baseDelayMs * Math.pow(2, attempt)
        lastError = new PostHogError({
          status: 429,
          message: `PostHog rate limit exceeded (attempt ${attempt + 1} of ${MAX_ATTEMPTS})`,
          endpoint,
        })
        if (attempt < MAX_ATTEMPTS - 1) {
          await sleep(delayMs)
          continue
        }
        throw lastError
      }

      // 5xx — server error: throw immediately, no retry
      if (response.status >= 500) {
        throw new PostHogError({
          status: response.status,
          message: `PostHog server error (${response.status}) on ${endpoint}`,
          endpoint,
        })
      }

      // 4xx (not 429) — client error: throw immediately
      let detail = ''
      try {
        const body = (await response.json()) as { detail?: string; message?: string }
        detail = body.detail ?? body.message ?? ''
      } catch (_) {
        // ignore parse error
      }
      throw new PostHogError({
        status: response.status,
        message: `PostHog returned ${response.status} on ${endpoint}${detail ? ': ' + detail : ''}`,
        endpoint,
      })
    }

    // Exhausted retries (always set when we reach this point via 429 path)
    throw lastError!
  }

  // -------------------------------------------------------------------------
  // Public API methods
  // -------------------------------------------------------------------------

  function listDashboards(limit = 100): Promise<DashboardListResponse> {
    return request(`${envBase}/dashboards/?limit=${limit}`, {
      method: 'GET',
    }) as Promise<DashboardListResponse>
  }

  function createDashboard(name: string, tags: string[]): Promise<Dashboard> {
    return request(`${envBase}/dashboards/`, {
      method: 'POST',
      body: JSON.stringify({ name, tags }),
    }) as Promise<Dashboard>
  }

  function getDashboard(id: number): Promise<Dashboard> {
    return request(`${envBase}/dashboards/${id}/`, {
      method: 'GET',
    }) as Promise<Dashboard>
  }

  function createInsight(name: string, query: Record<string, unknown>): Promise<Insight> {
    return request(`${envBase}/insights/`, {
      method: 'POST',
      body: JSON.stringify({ name, query }),
    }) as Promise<Insight>
  }

  function createInsightOnDashboard(
    name: string,
    query: Record<string, unknown>,
    dashboardId: number,
  ): Promise<Insight> {
    return request(`${envBase}/insights/`, {
      method: 'POST',
      body: JSON.stringify({ name, query, dashboards: [dashboardId] }),
    }) as Promise<Insight>
  }

  function getInsightByShortId(shortId: string): Promise<InsightListResponse> {
    return request(`${envBase}/insights/?short_id=${encodeURIComponent(shortId)}`, {
      method: 'GET',
    }) as Promise<InsightListResponse>
  }

  function runQuery(hogql: string): Promise<HogQLResult> {
    return request(`${projBase}/query/`, {
      method: 'POST',
      body: JSON.stringify({
        query: {
          kind: 'HogQLQuery',
          query: hogql,
        },
        refresh: 'blocking',
      }),
    }) as Promise<HogQLResult>
  }

  function listFeatureFlags(params: FeatureFlagListParams = {}): Promise<FeatureFlagListResponse> {
    const qs = new URLSearchParams()
    if (params.search != null && params.search !== '') qs.append('search', params.search)
    if (params.active != null && params.active !== '') qs.append('active', params.active)
    if (params.type != null && params.type !== '') qs.append('type', params.type)
    if (params.limit != null) qs.append('limit', String(params.limit))
    if (params.offset != null) qs.append('offset', String(params.offset))
    const query = qs.toString() ? `?${qs.toString()}` : ''
    return request(`${projBase}/feature_flags/${query}`, {
      method: 'GET',
    }) as Promise<FeatureFlagListResponse>
  }

  function getFeatureFlag(id: number | string): Promise<FeatureFlagSummary> {
    return request(`${projBase}/feature_flags/${id}/`, {
      method: 'GET',
    }) as Promise<FeatureFlagSummary>
  }

  function patchFeatureFlag(
    id: number | string,
    body: Record<string, unknown>,
  ): Promise<FeatureFlagSummary> {
    return request(`${projBase}/feature_flags/${id}/`, {
      method: 'PATCH',
      body: JSON.stringify(body),
    }) as Promise<FeatureFlagSummary>
  }

  function createFeatureFlag(
    key: string,
    body: Record<string, unknown> = {},
  ): Promise<FeatureFlagSummary> {
    return request(`${projBase}/feature_flags/`, {
      method: 'POST',
      body: JSON.stringify({ key, ...body }),
    }) as Promise<FeatureFlagSummary>
  }

  function getFeatureFlagActivity(
    id: number | string,
    limit?: number,
  ): Promise<FeatureFlagActivityResponse> {
    return request(`${projBase}/feature_flags/${id}/activity/?limit=${limit ?? 10}`, {
      method: 'GET',
    }) as Promise<FeatureFlagActivityResponse>
  }

  return {
    request,
    listDashboards,
    createDashboard,
    getDashboard,
    createInsight,
    createInsightOnDashboard,
    getInsightByShortId,
    runQuery,
    listFeatureFlags,
    getFeatureFlag,
    patchFeatureFlag,
    createFeatureFlag,
    getFeatureFlagActivity,
  }
}

import { PostHogError } from './posthog-client.js'
import type { PostHogConfig } from './posthog-client.js'
import * as spec from './dashboard-spec.js'

// ---------------------------------------------------------------------------
// Config types
// ---------------------------------------------------------------------------

export interface AppConfig extends PostHogConfig {
  achInsightId: string
  dashboardName: string
}

// ---------------------------------------------------------------------------
// Config resolution
// ---------------------------------------------------------------------------

export function resolveConfig(): AppConfig {
  return {
    host: process.env['POSTHOG_HOST'] ?? 'https://us.posthog.com',
    projectId: process.env['POSTHOG_PROJECT_ID'] ?? '39507',
    token: process.env['POSTHOG_PERSONAL_API_KEY'] ?? '',
    achInsightId: process.env['POSTHOG_ACH_INSIGHT_ID'] ?? 'drOq2lO5',
    dashboardName: process.env['POSTHOG_DASHBOARD_NAME'] ?? spec.name,
  }
}

export function requireToken(config: AppConfig): void {
  if (!config.token) {
    process.stderr.write(
      'Error: POSTHOG_PERSONAL_API_KEY is required for this command.\n' +
        'Set it in your environment: export POSTHOG_PERSONAL_API_KEY=phx_...\n',
    )
    process.exit(1)
  }
}

// ---------------------------------------------------------------------------
// Output helpers
// ---------------------------------------------------------------------------

export function out(data: unknown): void {
  process.stdout.write(JSON.stringify(data, null, 2) + '\n')
}

export function info(msg: string): void {
  process.stderr.write(msg + '\n')
}

export function handleApiError(err: unknown, context?: string): never {
  if (err instanceof PostHogError) {
    if (err.status === 401) {
      process.stderr.write(
        `Error: PostHog returned 401 (Unauthorized) on ${err.endpoint}\n` +
          'Verify that POSTHOG_PERSONAL_API_KEY is valid and has not expired.\n',
      )
    } else if (err.status === 403) {
      process.stderr.write(
        `Error: PostHog returned 403 (Forbidden) on ${err.endpoint}\n` +
          'Check that your API key has these scopes: dashboard:read, dashboard:write, insight:read, insight:write, query:read\n',
      )
    } else if (err.status === 429) {
      process.stderr.write(
        `Error: PostHog rate limit exceeded on ${err.endpoint} — tried 3 times.\n`,
      )
    } else {
      process.stderr.write(`Error: ${context ?? 'PostHog request failed'}: ${err.message}\n`)
    }
  } else {
    const message = err instanceof Error ? err.message : String(err)
    process.stderr.write(`Error: Connection to PostHog failed: ${message}\n`)
  }
  process.exit(1)
}

import { out, requireToken, handleApiError } from './config.js'
import type { AppConfig } from './config.js'
import { getFixture } from './fixtures.js'
import { createClient } from './posthog-client.js'

interface FlagsOptions {
  search?: string
  active?: string
  type?: string
  limit?: string
  name?: string
  tags?: string
  dryRun: boolean
}

function parseFlagsOptions(args: string[]): FlagsOptions {
  const opts: FlagsOptions = { dryRun: false }
  let i = 0
  while (i < args.length) {
    const arg = args[i]
    if (arg === undefined) break
    switch (arg) {
      case '--dry-run':
        opts.dryRun = true
        i++
        break
      case '--search':
        opts.search = args[i + 1]
        i += 2
        break
      case '--active':
        opts.active = args[i + 1]
        i += 2
        break
      case '--type':
        opts.type = args[i + 1]
        i += 2
        break
      case '--limit':
        opts.limit = args[i + 1]
        i += 2
        break
      case '--name':
        opts.name = args[i + 1]
        i += 2
        break
      case '--tags':
        opts.tags = args[i + 1]
        i += 2
        break
      default:
        i++
    }
  }
  return opts
}

export async function cmdFlags(args: string[], config: AppConfig): Promise<void> {
  let subcommand = 'list'
  let rest = args
  const firstArg = args[0]
  if (firstArg !== undefined && !firstArg.startsWith('--')) {
    subcommand = firstArg
    rest = args.slice(1)
  }

  const opts = parseFlagsOptions(rest)

  switch (subcommand) {
    case 'list': {
      if (opts.dryRun) {
        out(getFixture('flags'))
        return
      }
      requireToken(config)
      const client = createClient(config)
      try {
        const result = await client.listFeatureFlags({
          search: opts.search,
          active: opts.active,
          type: opts.type,
          limit: opts.limit !== undefined ? Number(opts.limit) : undefined,
        })
        out(result)
      } catch (err) {
        handleApiError(err, 'flags list failed')
      }
      break
    }
    case 'get': {
      const id = rest.find((a) => !a.startsWith('--'))
      if (!id) {
        process.stderr.write('Error: flags get requires a flag ID — ID is required\n')
        process.exit(2)
      }
      if (opts.dryRun) {
        out(getFixture('flags-get'))
        return
      }
      requireToken(config)
      const client = createClient(config)
      try {
        const result = await client.getFeatureFlag(id)
        out(result)
      } catch (err) {
        handleApiError(err, `flags get ${id} failed`)
      }
      break
    }
    case 'toggle': {
      const id = rest.find((a) => !a.startsWith('--'))
      if (!id) {
        process.stderr.write('Error: flags toggle requires a flag ID\n')
        process.exit(2)
      }
      if (opts.dryRun) {
        out(getFixture('flags-toggle'))
        return
      }
      requireToken(config)
      const client = createClient(config)
      try {
        const current = await client.getFeatureFlag(id)
        await client.patchFeatureFlag(id, { active: !current.active })
        out({
          id: current.id,
          key: current.key,
          active_before: current.active,
          active_after: !current.active,
        })
      } catch (err) {
        handleApiError(err, `flags toggle ${id} failed`)
      }
      break
    }
    case 'create': {
      const key = rest.find((a) => !a.startsWith('--'))
      if (!key) {
        process.stderr.write('Error: flags create requires a flag key\n')
        process.exit(2)
      }
      if (opts.dryRun) {
        out(getFixture('flags-create'))
        return
      }
      requireToken(config)
      const client = createClient(config)
      try {
        const body: Record<string, unknown> = { name: opts.name }
        if (opts.tags !== undefined) {
          body['tags'] = opts.tags.split(',')
        }
        const result = await client.createFeatureFlag(key, body)
        out(result)
      } catch (err) {
        handleApiError(err, `flags create ${key} failed`)
      }
      break
    }
    case 'update': {
      const id = rest.find((a) => !a.startsWith('--'))
      if (!id) {
        process.stderr.write('Error: flags update requires a flag ID\n')
        process.exit(2)
      }
      if (opts.dryRun) {
        out(getFixture('flags-update'))
        return
      }
      requireToken(config)
      const client = createClient(config)
      try {
        const body: Record<string, unknown> = {}
        if (opts.name !== undefined) body['name'] = opts.name
        if (opts.active !== undefined) body['active'] = opts.active === 'true'
        if (opts.tags !== undefined) body['tags'] = opts.tags.split(',')
        const result = await client.patchFeatureFlag(id, body)
        out(result)
      } catch (err) {
        handleApiError(err, `flags update ${id} failed`)
      }
      break
    }
    case 'activity': {
      const id = rest.find((a) => !a.startsWith('--'))
      if (!id) {
        process.stderr.write('Error: flags activity requires a flag ID\n')
        process.exit(2)
      }
      if (opts.dryRun) {
        out(getFixture('flags-activity'))
        return
      }
      requireToken(config)
      const client = createClient(config)
      try {
        const result = await client.getFeatureFlagActivity(
          id,
          opts.limit !== undefined ? Number(opts.limit) : 10,
        )
        out(result)
      } catch (err) {
        handleApiError(err, `flags activity ${id} failed`)
      }
      break
    }
    default:
      process.stderr.write(`Unknown flags subcommand: ${subcommand}\n`)
      process.exit(2)
  }
}

import { out, info, requireToken, handleApiError } from './config.js'
import type { AppConfig } from './config.js'
import { getFixture } from './fixtures.js'
import * as spec from './dashboard-spec.js'
import { createClient, PostHogError } from './posthog-client.js'

async function cmdCreateLive(config: AppConfig): Promise<void> {
  const client = createClient(config)
  const dashboardName = config.dashboardName
  const host = config.host
  const projectId = config.projectId

  // Step 1: Smoke test auth
  try {
    await client.listDashboards(1)
  } catch (err) {
    if (err instanceof PostHogError && err.status === 401) {
      process.stderr.write('Error: auth failed — verify POSTHOG_PERSONAL_API_KEY is valid.\n')
    } else if (err instanceof PostHogError && err.status === 403) {
      process.stderr.write(
        'Error: PostHog returned 403 — check that your API key has dashboard:read, dashboard:write, insight:read, insight:write, query:read scopes\n',
      )
    } else {
      const msg = err instanceof Error ? err.message : String(err)
      process.stderr.write(`Error: connection failed: ${msg}\n`)
    }
    process.exit(1)
  }

  // Step 2: List dashboards (up to 100)
  let dashboardList
  try {
    dashboardList = await client.listDashboards(100)
  } catch (err) {
    handleApiError(err, 'create: failed to list dashboards')
  }

  const allDashboards = dashboardList.results ?? []
  if (dashboardList.count > 100) {
    info('Warning: dashboard list may be truncated at 100 results')
  }

  // Step 3: Find or create dashboard
  const existing = allDashboards.find((d) => d.name === dashboardName && !d.deleted)
  let dashboardId: number

  if (existing) {
    dashboardId = existing.id
    info(`Found existing dashboard "${dashboardName}" (id: ${dashboardId})`)
  } else {
    info(`Creating dashboard "${dashboardName}"...`)
    let created
    try {
      created = await client.createDashboard(dashboardName, spec.tags)
    } catch (err) {
      handleApiError(err, 'create: failed to create dashboard')
    }
    dashboardId = created.id
    info(`Dashboard created (id: ${dashboardId})`)
  }

  // Step 4: Fetch full dashboard (includes tiles with nested insights)
  let dashboard
  try {
    dashboard = await client.getDashboard(dashboardId)
  } catch (err) {
    handleApiError(err, `create: failed to fetch dashboard ${dashboardId}`)
  }

  // Step 5: Build existing insight name → tile map from dashboard tiles
  const existingTiles = dashboard.tiles ?? []
  type ExistingTile = (typeof existingTiles)[number]
  const existingNameToTile: Record<string, ExistingTile> = {}
  for (const tile of existingTiles) {
    if (tile.insight && tile.insight.name) {
      existingNameToTile[tile.insight.name] = tile
    }
  }

  // Step 6: Create missing insights, attaching them to the dashboard via dashboards:[id]
  const tileResults: Array<{
    specTile: (typeof spec.tiles)[number]
    insightId: number | null
    status: 'existing' | 'created' | 'failed'
  }> = []
  let hasFailure = false

  for (const specTile of spec.tiles) {
    const existingTile = existingNameToTile[specTile.name]

    if (existingTile) {
      const tileInsight = existingTile.insight
      if (tileInsight) {
        info(`Skipping existing insight: "${specTile.name}" (id: ${tileInsight.id})`)
        tileResults.push({
          specTile,
          insightId: tileInsight.id,
          status: 'existing',
        })
      }
      continue
    }

    info(`Creating insight: "${specTile.name}"...`)
    try {
      const newInsight = await client.createInsightOnDashboard(
        specTile.name,
        specTile.query,
        dashboardId,
      )
      info(`  Created insight (id: ${newInsight.id})`)
      tileResults.push({
        specTile,
        insightId: newInsight.id,
        status: 'created',
      })
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err)
      process.stderr.write(`Error creating insight "${specTile.name}": ${msg}\n`)
      tileResults.push({
        specTile,
        insightId: null,
        status: 'failed',
      })
      hasFailure = true
    }
  }

  // Step 7: Emit result
  const tiles = tileResults.map((t) => ({
    name: t.specTile.name,
    insight_id: t.insightId,
    insight_url:
      t.insightId !== null ? `${host}/project/${projectId}/insights/${t.insightId}` : null,
    status: t.status,
  }))

  out({
    dashboard_id: dashboardId,
    dashboard_url: `${host}/project/${projectId}/dashboard/${dashboardId}`,
    tiles,
  })

  if (hasFailure) {
    process.exit(3)
  }
}

